"""Builds people-deep.json — deep People bank for the 2026 ECO's second-biggest
domain (33%). Situational/judgement, bilingual FR/EN, agile/hybrid-heavy.
Each item is tagged:
  - knowledge_area = per-task area id (pe_vision, pe_conflict, ...) for the quiz filter
    (stakeholder items reuse the existing 'stakeholder' KA, communication items reuse
     'comms' -> zero wiring for those two, and they finally give both KAs content)
  - pmbok_ref = PE.x  -> the map rolls each task up by ref via ProcessMastery (dynamic)
"""
import json, os

def it(area, ref, n, grp, comp, diff, fr_p, en_p, fr_o, en_o, ans, fr_r, en_r):
    return {"id": f"pe-x-{ref}-{n:02d}", "type": "scenario" if diff >= 2 else "mcq",
            "knowledge_area": area, "process_group": grp, "pmbok_ref": ref,
            "competency": comp, "difficulty": diff,
            "prompt": {"fr": fr_p, "en": en_p}, "options": {"fr": fr_o, "en": en_o},
            "answer_index": ans, "rationale": {"fr": fr_r, "en": en_r}}

